## Terraform Modules

Modules are reusable, composable infrastructure components:

```hcl
# modules/spring-boot-service/main.tf
# Reusable module for deploying a Spring Boot service
variable "service_name" { type = string }
variable "image" { type = string }
variable "replicas" { default = 2 }
variable "memory_limit" { default = "512Mi" }

resource "kubernetes_deployment" "app" {
  metadata { name = var.service_name }
  spec {
    replicas = var.replicas
    template {
      spec {
        container {
          name  = var.service_name
          image = var.image
          resources {
            limits   = { memory = var.memory_limit }
            requests = { memory = "256Mi" }
          }
        }
      }
    }
  }
}

# Usage — consume the module
module "order_service" {
  source       = "./modules/spring-boot-service"
  service_name = "order-service"
  image        = "registry/order-service:1.2.0"
  replicas     = 3
}
```

## Remote State and Workspaces

```hcl
# Remote state — shared, locked, encrypted
terraform {
  backend "s3" {
    bucket         = "my-terraform-state"
    key            = "${var.environment}/eks/terraform.tfstate"
    region         = "us-east-1"
    encrypt        = true
    dynamodb_table = "terraform-locks"
  }
}

# Workspaces for environment isolation
# terraform workspace new prod
# terraform workspace select prod
locals {
  env_config = {
    dev  = { instance_type = "t3.small",  min_nodes = 1 }
    prod = { instance_type = "m5.xlarge", min_nodes = 3 }
  }
  config = local.env_config[terraform.workspace]
}

resource "aws_eks_node_group" "main" {
  instance_types = [local.config.instance_type]
  scaling_config {
    min_size = local.config.min_nodes
  }
}
```
